1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	};
8	
9	type Item = { type: string };
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
12	
13	const basePremiumFor = (item: Item) => BASE_PREMIUM[item.type];
14	
15	const quote = (step: QuoteStep) => {
16	  const itemsTotal = step.items.reduce(
17	    (sum, item) => sum + basePremiumFor(item),
18	    0,
19	  );
20	  return { premium: itemsTotal + PROCESSING_FEE };
21	};
22	
23	export const run = (input: Scenario): unknown => {
24	  return { results: input.steps.map(quote) };
25	};
