1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / simplest
6	  it("empty item list quote → premium 5 G (only processing fee)", () => {
7	    const result = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (each + processing fee, no other modifiers)
15	  it("quote single sword → 100 G base + 5 fee = 105 G", () => {
16	    const result = run({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("quote single amulet → 60 G base + 5 fee = 65 G", () => {
23	    const result = run({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("quote single staff → 80 G base + 5 fee = 85 G", () => {
30	    const result = run({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it.todo("quote single potion → 40 G base + 5 fee = 45 G");
37	
38	  // Component base premiums
39	  it.todo("quote single rune → 25 G base + 5 fee = 30 G");
40	  it.todo("quote single moonstone → 25 G base + 5 fee = 30 G");
41	
42	  // Block of 3 alike components
43	  it.todo("quote 2 runes → 50 G base + 5 fee = 55 G");
44	  it.todo("quote 3 runes → 60 G base (block) + 5 fee = 65 G");
45	  it.todo("quote 4 runes → 100 G base (no block, requires exactly 3) + 5 fee = 105 G");
46	  it.todo("quote 7 runes → 175 G base + 5 fee = 180 G");
47	
48	  // Alike components — different types do not form a block together
49	  it.todo("quote 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G");
50	  it.todo("quote 3 runes + 3 moonstones → 120 G base (two separate blocks) + 5 fee = 125 G");
51	
52	  // Item-specific modifiers: cursed surcharge applies to the cursed item only
53	  it.todo("quote cursed sword on item-only scope → 100 + 50 curse + 5 fee = 155 G");
54	
55	  // High enchantment item-specific
56	  it.todo("quote sword enchantment 5 → 100 + 30 high-enchant + 5 fee = 135 G (threshold)");
57	  it.todo("quote sword enchantment 4 → 100 + 5 fee = 105 G (below threshold)");
58	  it.todo("quote cursed sword enchantment 5 → 100 + 50 + 30 + 5 = 185 G");
