62	  it.todo("quote single sword with customer 2 years → 100 - 20 loyalty + 5 fee = 85 G (threshold)");
63	  it.todo("first quote in scenario triggers first insurance surcharge → 100 + 10 + 5 = 115 G");
64	  it.todo("second quote in scenario gets follow-up contract discount → 100 + 10 first ins - 15 follow-up + 5 = 100 G");
65	
